import{_ as s,o as a,c as n,a0 as i}from"./chunks/framework.CSK6mTG2.js";const k=JSON.parse('{"title":"大模型是什么：从\\"猜词游戏\\"到\\"数字大脑\\"","description":"","frontmatter":{"title":"大模型是什么：从\\"猜词游戏\\"到\\"数字大脑\\"","author":"唐超","date":"2026-07-03"},"headers":[],"relativePath":"menuAI/what-is-llm.md","filePath":"menuAI/what-is-llm.md"}'),e={name:"menuAI/what-is-llm.md"};function o(l,t,p,h,r,d){return a(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="大模型是什么-从-猜词游戏-到-数字大脑" tabindex="-1">大模型是什么：从&quot;猜词游戏&quot;到&quot;数字大脑&quot; <a class="header-anchor" href="#大模型是什么-从-猜词游戏-到-数字大脑" aria-label="Permalink to &quot;大模型是什么：从&quot;猜词游戏&quot;到&quot;数字大脑&quot;&quot;">​</a></h1><h2 id="一个简单的类比" tabindex="-1">一个简单的类比 <a class="header-anchor" href="#一个简单的类比" aria-label="Permalink to &quot;一个简单的类比&quot;">​</a></h2><p>想象你在玩一个游戏：给你一句话的前半段，你来猜下一个字。</p><blockquote><p>&quot;今天天气真___&quot;</p></blockquote><p>你会猜&quot;好&quot;、&quot;热&quot;、&quot;冷&quot;、&quot;不错&quot;。如果我再告诉你：&quot;今天是晴天，气温 28 度&quot;，你会更自信地猜&quot;好&quot;或&quot;热&quot;。</p><p><strong>大语言模型（LLM）本质上就是一个超级加强版的&quot;猜词游戏&quot;。</strong> 它学习了海量文本中字词之间的统计规律，当你给它一段文字，它会计算每个可能的下一个词的概率，然后选一个&quot;最合理&quot;的词接上。</p><h2 id="三个核心概念" tabindex="-1">三个核心概念 <a class="header-anchor" href="#三个核心概念" aria-label="Permalink to &quot;三个核心概念&quot;">​</a></h2><h3 id="_1-token-模型的-最小思考单元" tabindex="-1">1. Token：模型的&quot;最小思考单元&quot; <a class="header-anchor" href="#_1-token-模型的-最小思考单元" aria-label="Permalink to &quot;1. Token：模型的&quot;最小思考单元&quot;&quot;">​</a></h3><p>模型不直接处理&quot;字&quot;，它处理的是 <strong>Token</strong>——介于&quot;字&quot;和&quot;词&quot;之间的语义单元。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入文本：&quot;人工智能正在改变世界&quot;</span></span>
<span class="line"><span>         ↓ Tokenizer 分词</span></span>
<span class="line"><span>Token序列：[&quot;人工智能&quot;, &quot;正在&quot;, &quot;改变&quot;, &quot;世界&quot;]</span></span>
<span class="line"><span>         ↓ 映射到词表 ID</span></span>
<span class="line"><span>数字序列：[38472, 1045, 2893, 1582]</span></span></code></pre></div><p>每个数字 ID 对应词表（Vocabulary）中的一个 token。GPT-4 的词表约 10 万个 token，DeepSeek 的词表约 12.8 万个。模型始终在和这些数字打交道，而不是汉字或英文单词。</p><h3 id="_2-神经网络-一个巨大的概率计算器" tabindex="-1">2. 神经网络：一个巨大的概率计算器 <a class="header-anchor" href="#_2-神经网络-一个巨大的概率计算器" aria-label="Permalink to &quot;2. 神经网络：一个巨大的概率计算器&quot;">​</a></h3><p>如果你把词表里的 10 万个 token 排成一排，模型做的事情就是：</p><blockquote><p><strong>给定前文，计算出 10 万个 token 各自出现在下一个位置的概率。</strong></p></blockquote><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：&quot;中国的首都是&quot;</span></span>
<span class="line"><span>      ↓ 神经网络计算</span></span>
<span class="line"><span>输出概率：</span></span>
<span class="line"><span>  北京: 0.92  ← 最高</span></span>
<span class="line"><span>  上海: 0.03</span></span>
<span class="line"><span>  广州: 0.01</span></span>
<span class="line"><span>  ...（剩余 99997 个 token 的概率）</span></span></code></pre></div><p>这个过程背后是数十亿甚至数千亿个参数（weights）在做矩阵乘法。<strong>参数就是模型从训练数据中学到的&quot;知识&quot;，本质上是一串浮点数字。</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 一个极度简化的&quot;模型&quot;思维方式</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 真实的 LLM 比这复杂数百万倍</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tiny_model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(context: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) -&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dict</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;&quot;&quot;根据上下文预测下一个词的概率分布&quot;&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    patterns </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;中国的首都是&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;北京&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.92</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;上海&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.03</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;广州&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.01</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;1+1=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.99</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.005</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.005</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> patterns.get(context, {})</span></span></code></pre></div><h3 id="_3-参数-模型记忆的-脑细胞" tabindex="-1">3. 参数：模型记忆的&quot;脑细胞&quot; <a class="header-anchor" href="#_3-参数-模型记忆的-脑细胞" aria-label="Permalink to &quot;3. 参数：模型记忆的&quot;脑细胞&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th style="text-align:center;">参数量</th><th>类比</th></tr></thead><tbody><tr><td>GPT-2</td><td style="text-align:center;">1.5 亿</td><td>老鼠大脑</td></tr><tr><td>GPT-3</td><td style="text-align:center;">1750 亿</td><td>猫的大脑</td></tr><tr><td>GPT-4</td><td style="text-align:center;">~1.8 万亿（MoE）</td><td>接近人脑复杂度</td></tr><tr><td>DeepSeek V3</td><td style="text-align:center;">6710 亿（MoE，激活 370 亿）</td><td>专家团队协同</td></tr></tbody></table><blockquote><p><strong>参数越多 ≠ 一定越聪明</strong>，但更多参数通常能捕捉更复杂的语言规律。</p></blockquote><h2 id="训练-vs-推理-两段截然不同的人生" tabindex="-1">训练 vs 推理：两段截然不同的人生 <a class="header-anchor" href="#训练-vs-推理-两段截然不同的人生" aria-label="Permalink to &quot;训练 vs 推理：两段截然不同的人生&quot;">​</a></h2><p>这是理解大模型最重要的概念区分之一。</p><h3 id="训练-training-模型的-求学期" tabindex="-1">训练（Training）：模型的&quot;求学期&quot; <a class="header-anchor" href="#训练-training-模型的-求学期" aria-label="Permalink to &quot;训练（Training）：模型的&quot;求学期&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌──────────────┐</span></span>
<span class="line"><span>海量文本 ──────────→│   大模型训练   │──→ 模型权重文件</span></span>
<span class="line"><span>（万亿级 token）    │ （数周～数月）  │   （几百 GB）</span></span>
<span class="line"><span>                    └──────────────┘</span></span></code></pre></div><p>训练过程的核心是<strong>自监督学习</strong>：</p><ol><li>拿来一段文本，遮住后半部分</li><li>让模型预测被遮住的部分</li><li>对比预测结果和真实文本，&quot;批评&quot;模型</li><li>调整参数，降低预测误差</li><li>重复万亿次</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>训练数据：&quot;床前明月光，疑是地上霜。举头望明月，低头思故乡。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>步骤1：喂入 &quot;床前明月光，疑是地上霜。举头望明月，&quot;</span></span>
<span class="line"><span>步骤2：模型预测 → &quot;故乡。&quot;</span></span>
<span class="line"><span>步骤3：真实答案是 &quot;低头思故乡。&quot; → 错了，扣分！</span></span>
<span class="line"><span>步骤4：梯度下降，调整参数，下次更容易预测对</span></span></code></pre></div><p><strong>训练一次 GPT-4 级别的模型，成本高达数千万到上亿美元</strong>，需要上万张 GPU 跑几个月。</p><h3 id="推理-inference-模型-上班干活" tabindex="-1">推理（Inference）：模型&quot;上班干活&quot; <a class="header-anchor" href="#推理-inference-模型-上班干活" aria-label="Permalink to &quot;推理（Inference）：模型&quot;上班干活&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌──────────────┐</span></span>
<span class="line"><span>你的 prompt ───────→│  已训练的模型  │──→ 逐 token 输出</span></span>
<span class="line"><span>（几百 token）      │ （前向传播）   │   （流式生成）</span></span>
<span class="line"><span>                    └──────────────┘</span></span></code></pre></div><p>推理是<strong>纯前向计算</strong>，不再修改参数：</p><ol><li>接收输入 prompt</li><li>逐层计算（矩阵乘法）</li><li>输出下一个 token 的概率分布</li><li>选一个 token 作为输出</li><li>把新 token 接在末尾，重复步骤 2～4</li></ol><p><strong>推理是&quot;只读&quot;操作，不会改变模型的任何参数。</strong> 这就是为什么 ChatGPT 不会&quot;记住&quot;你和它聊过什么——对话历史只存在于当前会话的上下文中，不写入模型权重。</p><h3 id="训练-vs-推理-对比" tabindex="-1">训练 vs 推理 对比 <a class="header-anchor" href="#训练-vs-推理-对比" aria-label="Permalink to &quot;训练 vs 推理 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>训练</th><th>推理</th></tr></thead><tbody><tr><td><strong>目的</strong></td><td>学习知识</td><td>回答问题</td></tr><tr><td><strong>参数</strong></td><td>不断更新</td><td>冻结不变</td></tr><tr><td><strong>硬件需求</strong></td><td>数千张 GPU</td><td>1～8 张 GPU</td></tr><tr><td><strong>耗时</strong></td><td>数周至数月</td><td>毫秒到秒级</td></tr><tr><td><strong>成本</strong></td><td>千万美元级</td><td>几分钱/次</td></tr><tr><td><strong>数据方向</strong></td><td>反向传播（反向）</td><td>前向传播（正向）</td></tr><tr><td><strong>类比</strong></td><td>学生刷题备考</td><td>学生上考场答题</td></tr></tbody></table><h2 id="大模型的-大-在哪" tabindex="-1">大模型的&quot;大&quot;在哪？ <a class="header-anchor" href="#大模型的-大-在哪" aria-label="Permalink to &quot;大模型的&quot;大&quot;在哪？&quot;">​</a></h2><h3 id="_1-数据量大" tabindex="-1">1. 数据量大 <a class="header-anchor" href="#_1-数据量大" aria-label="Permalink to &quot;1. 数据量大&quot;">​</a></h3><p>GPT-4 的训练数据约 <strong>13 万亿 token</strong>——相当于把人类历史上几乎所有公开书籍、论文、网页、代码都读了一遍。</p><h3 id="_2-参数多" tabindex="-1">2. 参数多 <a class="header-anchor" href="#_2-参数多" aria-label="Permalink to &quot;2. 参数多&quot;">​</a></h3><p>从 GPT-2 的 15 亿到 GPT-4 的 1.8 万亿，增长了 1000 多倍。每增加一个数量级的参数，模型就会涌现出新的能力（这种现象被称为&quot;涌现&quot; Emergence）。</p><h3 id="_3-算力大" tabindex="-1">3. 算力大 <a class="header-anchor" href="#_3-算力大" aria-label="Permalink to &quot;3. 算力大&quot;">​</a></h3><p>训练 GPT-4 级别的模型需要约 <strong>2 万张 A100 GPU 跑 90～100 天</strong>，总耗电量相当于一个小型城镇一年的用电量。</p><h2 id="大模型为什么-会犯错" tabindex="-1">大模型为什么&quot;会犯错&quot; <a class="header-anchor" href="#大模型为什么-会犯错" aria-label="Permalink to &quot;大模型为什么&quot;会犯错&quot;&quot;">​</a></h2><p>理解了大模型的本质是&quot;猜词游戏&quot;，就能理解它的局限：</p><ol><li><strong>不是真正&quot;理解&quot;</strong>：模型只是学到了字词之间的统计相关性，没有真正的意识和理解</li><li><strong>概率驱动</strong>：它给出的不是&quot;正确答案&quot;，而是&quot;最可能的接续&quot;</li><li><strong>幻觉（Hallucination）</strong>：当训练数据中没有相关信息，模型会&quot;编造&quot;——因为从概率上，总有一个词比沉默更合理</li><li><strong>上下文窗口限制</strong>：模型不能无限回顾历史，长对话会&quot;遗忘&quot;早期内容</li></ol><h2 id="你应该记住什么" tabindex="-1">你应该记住什么 <a class="header-anchor" href="#你应该记住什么" aria-label="Permalink to &quot;你应该记住什么&quot;">​</a></h2><blockquote><p>大语言模型 = 海量参数 + 海量训练数据 + 超级算力</p><p>它做的事 = 给定上文，猜下一个 token 的概率分布</p><p>训练 = 调整参数让猜得更准，推理 = 用固定参数干活</p><p>它不是真正的&quot;智能&quot;，但统计规律足够强大时，看起来和智能很难区分。</p></blockquote><hr><p><em>下一篇：大模型如何&quot;看懂&quot;文字——从 One-Hot 到词嵌入</em></p>`,49)])])}const q=s(e,[["render",o]]);export{k as __pageData,q as default};
